<template>
  <div>
    <b-container fluid>
      <b-row>
        <b-col>
          <h5 style="font-size: 1rem">
            {{ nomUser }}, seleccione la fecha que desea agendar:
          </h5>
        </b-col>
      </b-row>
      <b-row class="mb-3 mt-2">
        <b-col class="text-center">
          <b-calendar
            block
            v-model="tmpDateSelected"
            @context="onContext"
            locale="es"
            :min="minDate"
            :start-weekday="1"
            @selected="selectDate"
            :date-disabled-fn="dateDisabled"
            selected-variant="primary"
            today-variant="primary"
            small
            id="calendar"
            dark="true"
          ></b-calendar>
        </b-col>
      </b-row>
      <b-row>
        <b-col>
          <b-container>
            <b-row>
              <b-col col-sm="12" class="mt-2 text-center">
                <b-button
                  :pressed="true"
                  type="button"
                  variant="primary"
                  @click="goStepPersonalInfo"
                >
                  <!-- <div class="h5 mb-2 mt-1"> -->
                  <b-icon
                    icon="person-fill"
                    aria-hidden="true"
                    class="mr-2"
                  ></b-icon>
                  <!-- </div> -->
                  <p class="m-0" style="font-size: 0.8rem">Datos Personales</p>
                </b-button>
              </b-col>
              <b-col col-sm="12" class="mt-2 text-center">
                <b-button
                  :pressed="true"
                  type="button"
                  variant="primary"
                  @click="goStepSchedule"
                >
                  <!-- <div class="h5 mb-2 mt-1"> -->
                  <b-icon
                    icon="clock-history"
                    aria-hidden="true"
                    class="mr-2"
                  ></b-icon>
                  <!-- </div> -->
                  <p class="m-0" style="font-size: 0.8rem">
                    Seleccionar Horario
                  </p>
                </b-button>
              </b-col>
            </b-row>
          </b-container>
        </b-col>
      </b-row>
    </b-container>
  </div>
</template>

<script>
import moment from "moment";
import { mapActions, mapState } from "vuex";

export default {
  name: "StepDate",
  components: {},
  data() {
    return {
      tmpDateSelected: null,
      context: null,
      minDate: new Date(moment()), //new Date(moment().add(1, "days")),
    };
  },
  computed: {
    ...mapState("reserves", ["dateSelected"]),
    ...mapState("users", ["userData"]),
    nomUser() {
      return this.userData.name + " " + this.userData.lastname;
    },
  },
  mounted() {
    //Verificamos si tenemos datos del usuario, si no se tienen se va al inicio
    if (this.userData.document == "") {
      this.$router.replace("/");
    }

    //Asignamos fecha seleccionada si la hay
    this.tmpDateSelected = this.dateSelected;
  },
  methods: {
    ...mapActions("reserves", ["setReserveDate"]),
    onContext(ctx) {
      this.context = ctx;
    },
    goStepSchedule() {
      if (this.tmpDateSelected == "") {
        this.$toastr.e("Debe seleccionar una fecha.", "Fecha de Reserva");
        return;
      }

      //Asignamos en memoria la fecha seleccionada
      this.setReserveDate(this.tmpDateSelected);

      //Vamos al siguiente paso
      this.$router.push("StepSchedule");
    },
    goStepPersonalInfo() {
      //Vamos al paso anterior
      this.$router.go(-1);
    },
    selectDate(ctx) {
      this.tmpDateSelected = ctx;
      this.goStepSchedule();
    },
    dateDisabled(ymd, date) {
      // Disable weekends (Sunday = `0`)
      const weekday = date.getDay();
      const day = date.getDate();
      return weekday === 0 || this.isFestive(date);
    },
    isFestive(date) {
      let festivesArray = [
        "2021-04-01",
        "2021-04-02",
        "2021-05-01",
        "2021-05-17",
        "2021-06-07",
        "2021-06-14",
        "2021-07-05",
        "2021-07-20",
      ];

      return festivesArray.indexOf(moment(date).format("YYYY-MM-DD")) >= 0
        ? true
        : false;
    },
  },
};
</script>

